var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"루루!","JPN":"ルル！","ENG":"Lulu!","TWN":"露露！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"NIGHTMARE_DREAM_HORN_FAKE","text":{"KOREA":"아. 글린다.","JPN":"あ。グリンダ。","ENG":"Oh, Glinda.","TWN":"喔，格琳達。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"어딜 갈 땐 일행한테 말이라도 해주라고.","JPN":"どこかに行く時には一緒にいる人に話くらいはして。","ENG":"Hey, at least tell me if you’re gonna go somewhere, okay?","TWN":"你要去別的地方之前也先說一聲吧。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"NIGHTMARE_DREAM_HORN_FAKE","text":{"KOREA":"미안. 저기에 사람이 있어서.","JPN":"ごめん。あそこに人がいたから。","ENG":"Sorry. I saw a person over there.","TWN":"對不起，那裡有個人。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"엥? 노숙 선배님 계시네.","JPN":"え？　野宿の先輩じゃん。","ENG":"Huh? A homeless person?","TWN":"嗯？是原本就在這睡覺的前輩嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"여기선 못 자겠다. 루루, 다른 데로 가자.","JPN":"ここでは寝られないなぁ。ルル、他のところに行こ。","ENG":"Guess this place is taken. Lulu, let’s go somewhere else.","TWN":"那這裡不行，露露，我們再找別的地方吧！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"NIGHTMARE_DREAM_HORN_FAKE","text":{"KOREA":"저 사람한테…… 가야 돼.","JPN":"あの人のところに……行かなきゃ。","ENG":"I need to go... to that person.","TWN":"我要過去……找那個人。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……뭐 언제는 뭐 내 말 들었나.","JPN":"……まあ。私の言うことなんて聞いたことないか。","ENG":"Sure... It’s not like you ever really listened to me.","TWN":"……喔，反正我說的話你都沒在聽的。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"NIGHTMARE_DREAM_HORN_FAKE","text":{"KOREA":"글린다. 부탁이 있어.","JPN":"グリンダ。頼みがあるの。","ENG":"Glinda, I need a favor.","TWN":"格琳達，我要拜託你一件事。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"부탁?","JPN":"頼み？","ENG":"A favor?","TWN":"拜託我？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"혹시 나쁜 짓하려는 거면…… 내가 너랑 얽히긴 했어도 진짜 공범이 되는 건 사양하고 싶은데.","JPN":"悪さをするつもりなら……アンタとつるんではいるけど、本当に共犯になるのは遠慮しておきたいね。","ENG":"If it’s something bad... I don’t want to really become your accomplice, you know...","TWN":"是要做壞事嗎？……雖然我現在和你牽扯在一起，但我沒有想真的成為共犯喔！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NIGHTMARE_DREAM_HORN_FAKE","text":{"KOREA":"그런 건 아니야.","JPN":"そんなのじゃないよ。","ENG":"It’s nothing like that.","TWN":"不是要做壞事。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"NIGHTMARE_DREAM_HORN_FAKE","text":{"KOREA":"잠시만…… 날 지켜줄 수 있어?","JPN":"ちょっとの間だけ……私を守ってくれる？","ENG":"Could you... protect me for a bit?","TWN":"你可以……暫時保護我一下嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그게 무슨 소리야?","JPN":"どういうこと？","ENG":"What are you talking about?","TWN":"這什麼意思？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"NIGHTMARE_DREAM_HORN_FAKE","text":{"KOREA":"아주 잠깐, 잠깐이면 돼.","JPN":"本当にちょっと、ちょっとでいいの。","ENG":"It’ll only take a few minutes...","TWN":"只要一下就好，拜託。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"어…… 내 물몸으로 뭘 어떻게 지켜야 될 진 모르겠지만, 일단은 알겠어.","JPN":"え……私の弱っちい体で何をどうやって守ればいいのかわかんないけど、とりあえずやってみるよ。","ENG":"Uh... I'm not sure how my squishy body is supposed to protect you, but sure?","TWN":"喔……雖然我手無縛雞之力，不知道拿什麼保護你，但就先這樣吧！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"?! 뭐, 뭐야! 루루! 정신 차려! 루루!!!","JPN":"！？　な、なに！　ルル！　しっかりしなさいよ！　ルル！！","ENG":"?! W-what?! Lulu! Wake up! Lulu!!!","TWN":"？！這是怎樣？露露！你醒醒！露露！！！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"루루! 정신이 들어?","JPN":"ルル！　気がついた？","ENG":"Lulu! Are you okay?","TWN":"露露！你醒啦？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"갑자기 쓰러지는 게 어딨어! 뭐 문제라도 있는 거 아냐?","JPN":"いきなり倒れるなんて！　どっか悪いんじゃない？","ENG":"Why’d you faint all of a sudden? Are you sick or something?","TWN":"哪有人會這樣突然昏倒的！你是不是哪裡有問題？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"어? 너……","JPN":"えっ？　アンタ……","ENG":"Hmm? You’re...","TWN":"嗯？你……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그 모습은 대체……?","JPN":"その姿はいったい……？","ENG":"Your appearance...","TWN":"你的樣子……？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NIGHTMARE_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"너…… 카운터였어?","JPN":"アンタ……カウンターだったの？","ENG":"Are you... a Counter?","TWN":"你……是制裁者嗎？"},"stage":{"bg":"NIGHTMARE_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그 뿔이며 불꽃이며…….","JPN":"その角に炎……","ENG":"The horns and that flame...","TWN":"怎麼有角，又有火……"},"stage":{"bg":"NIGHTMARE_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"많이 이상하니?","JPN":"そんなに変？","ENG":"Is it weird?","TWN":"很奇怪嗎？"},"stage":{"bg":"NIGHTMARE_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"이상한 게 아니라 신기한 거지! 카운터 보기가 어디 쉬운 줄 알아?","JPN":"変じゃなくてかっこいいよ！　カウンターってそうそう見ないから。","ENG":"It’s not weird, it’s cool! It’s not every day you get to see a Counter!","TWN":"不是奇怪，是很神奇！平時可不容易見到制裁者欸！"},"stage":{"bg":"NIGHTMARE_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그 불꽃은 뭐야? 색이 그냥 불이랑은 좀 다른데.","JPN":"その炎は何？　ただの火とは色がちょっと違うけど。","ENG":"But what’s that flame? The color’s different from what I’m used to.","TWN":"那團火是什麼？和一般的火好像不太一樣？"},"stage":{"bg":"NIGHTMARE_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"안 뜨거워 보여. 오히려 시리도록 차가운 느낌……. 나도 만져봐도 돼?","JPN":"熱くはなさそう。むしろ冷ややかで冷たい感じ……触ってみてもいい？","ENG":"It doesn’t appear to be hot... Feels more like it’ll be icy cold... Can I touch it?","TWN":"好像不會燙，反而有種冷冷的感覺……我可以摸摸看嗎？"},"stage":{"bg":"NIGHTMARE_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"안 돼!","JPN":"ダメ！","ENG":"No!","TWN":"不可以！"},"stage":{"bg":"NIGHTMARE_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_FIRE_05"},{"id":"L42_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"깜짝이야!","JPN":"ビックリした！","ENG":"Whoa!","TWN":"嚇我一跳！"},"stage":{"bg":"NIGHTMARE_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"불꽃은 절대 건들지 마.","JPN":"炎には絶対触れないで。","ENG":"Don’t touch the flame.","TWN":"這團火絕對不能摸！"},"stage":{"bg":"NIGHTMARE_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"아, 알았어. 뭘 그렇게까지…….","JPN":"わ、わかったよ。何をそこまで……","ENG":"O-okay... You could’ve just said that...","TWN":"喔，不摸就不摸，幹嘛這麼大聲……"},"stage":{"bg":"NIGHTMARE_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"이게 뭐, 중요한 거라도 돼?","JPN":"これが何か重要なものなの？","ENG":"What is it? Is it something important?","TWN":"這是很重要的東西嗎？"},"stage":{"bg":"NIGHTMARE_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"이 불꽃은…… 이 사람의 악몽이야.","JPN":"この炎は……この人の悪夢だよ。","ENG":"This flame... It’s this person’s nightmare.","TWN":"這團火……就是這個人的惡夢。"},"stage":{"bg":"NIGHTMARE_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"악몽……? 그러고 보니 저 사람…… 표정이 편안해졌네.","JPN":"悪夢……？　そういえばあの人……顔が安らかになってる。","ENG":"Nightmare...? Now that you mention it... He does look relieved.","TWN":"惡夢……？這麼說來，他的表情……好像沒那麼痛苦咧？"},"stage":{"bg":"NIGHTMARE_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"으응. 더 이상 악몽을 꾸지 않으니까.","JPN":"うん。もう悪夢を見てないから。","ENG":"Mm-hmm. He won’t have any more nightmares.","TWN":"嗯嗯，以後他不會再做惡夢了。"},"stage":{"bg":"NIGHTMARE_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"힘들었을 거야. 매일 밤 악몽에 시달렸을 테니.","JPN":"辛かったと思うよ。毎晩悪夢に苦しんでただろうから。","ENG":"It must’ve been hard having nightmares every night.","TWN":"每晚都做惡夢應該很辛苦吧？"},"stage":{"bg":"NIGHTMARE_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……이 부근 사람들은 다 그래.","JPN":"……この辺りの人はみんなそうだよ。","ENG":"Everyone around here suffers from nightmares.","TWN":"……這一帶的人誰不是這樣，"},"stage":{"bg":"NIGHTMARE_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"위저드 애들은 말할 것도 없고.","JPN":"ウィザードの子たちは言うまでもない。","ENG":"The Wizard kids are no exception.","TWN":"更別說是魔法師的孩子們 。"},"stage":{"bg":"NIGHTMARE_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"언젠가부터 다들 악몽을 꾼다는데…… 대책은 없고…….","JPN":"いつの頃からかみんな悪夢を見るというけど……対策もないし……","ENG":"They all started having them one day... But there seems to be no remedy...","TWN":"不知道是從什麼時候開始的，大家都在做惡夢……但又無可奈何……"},"stage":{"bg":"NIGHTMARE_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NIGHTMARE_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"피곤함을 잊으려고 <color=#ffd34c>헤이븐 랜드</color>를 가고, 놀고, 먹고 마시다 잠들면 또 악몽을 꾸고.","JPN":"疲れを忘れようと<color=#ffd34c>ヘイブンランド</color>に行って、遊んで、食べて飲んで、寝るとまた悪夢を見る。","ENG":"People visit <color=#ffd34c>Havenland</color> to play games, eat, and drink away their exhaustion... But every single one of them still gets nightmares at night.","TWN":"想說要暫時忘記疲勞，就到<color=#ffd34c>天堂樂園</color>去放鬆，小酌一杯，結果入睡後還是做惡夢。"},"stage":{"bg":"NIGHTMARE_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"네가 말한 그곳…… 모두 무서운 악몽을 꾸고 있었어.","JPN":"グリンダが言ったあそこ……みんな怖い悪夢を見てたよ。","ENG":"That place you said... They all had scary nightmares.","TWN":"你說的那個地方……大家都在做可怕的惡夢。"},"stage":{"bg":"NIGHTMARE_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"아참. 너 우리 조직 수배범이었지? 신원 미상의 침입자랬나.","JPN":"そうだ。アンタ、ウチの組織の手配犯だったね。身元不明の侵入者だっけ？","ENG":"Oh, right! You’re a wanted criminal over there. An unidentified intruder, was it?","TWN":"對吼，你是我們組織內的通緝犯對吧？説是身分不明的侵入者嗎？"},"stage":{"bg":"NIGHTMARE_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"으응.","JPN":"うん。","ENG":"…Yes.","TWN":"嗯嗯。"},"stage":{"bg":"NIGHTMARE_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"스파이도 뭣도 아닌 애 하나에 삼엄한 경비가 뚫렸다는 거 알면 헤이븐 형님도 속 꽤나 쓰리시겠네.","JPN":"スパイでもなんでもない、子ども一人にあの厳しい警戒をくぐり抜けられたと知ったら、ヘイブン兄貴も相当な痛手だろうね。","ENG":"I can see why Mr. Haven is upset about how easily a little girl who isn't even a spy got through his security.","TWN":"又不是什麼特務，區區一個小丫頭就能突破森嚴的戒備，這事要是被天堂大哥知道，他應該會很頭痛吧？"},"stage":{"bg":"NIGHTMARE_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"악몽의 힘을 부추기는 사람은…… 싫어.","JPN":"悪夢の力をあおりたてる人は……嫌い。","ENG":"I don’t like... whoever is fueling the nightmares.","TWN":"我討厭……煽動惡夢之力的人。"},"stage":{"bg":"NIGHTMARE_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"헤이븐 형님 말하는 거야?","JPN":"ヘイブン兄貴のこと？","ENG":"Oh, are you talking about Mr. Haven?","TWN":"你是說天堂大哥？"},"stage":{"bg":"NIGHTMARE_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"너무 그러지 마. 헤이븐 형님의 철학이 뭔지 알아?","JPN":"そう嫌わないでよ。ヘイブン兄貴の哲学、知ってる？","ENG":"Don’t be so harsh on him. You know what his philosophy is?","TWN":"你別這樣，你知道天堂大哥的座右銘是什麼嗎？"},"stage":{"bg":"NIGHTMARE_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"<color=#ffd34c> 인생은 짧고 놀 건 많다.</color> 즐겁게 살다만 가도 모자란 인생이라는 거지.","JPN":"<color=#ffd34c>人生短し、遊びは多し。</color>楽しく遊んで暮らすには人生は短いってこと。","ENG":"<color=#ffd34c> Life is short with much to enjoy.</color> In short, he thinks there’s so much in life to enjoy to waste it away.","TWN":"<color=#ffd34c>人生苦短，及時行樂。</color>意思就是人生就是要盡情享樂。"},"stage":{"bg":"NIGHTMARE_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그래서 <color=#ffd34c>헤이븐 랜드</color>도 만드신 거라니까?","JPN":"だから<color=#ffd34c>ヘイブンランド</color>を作ったんだよ。","ENG":"That’s why he created <color=#ffd34c>Havenland</color>.","TWN":"所以他才會打造出<color=#ffd34c>天堂樂園</color>嗎？"},"stage":{"bg":"NIGHTMARE_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"하지만 악몽에 나온 그 사람은 그럼……","JPN":"でも、それじゃあ悪夢に出てきたあの人は……","ENG":"But then that person from the nightmares...","TWN":"可是出現在惡夢裡的那個人……"},"stage":{"bg":"NIGHTMARE_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"아니야. 글린다가 그렇게 얘기한다면 나도 그 사람을 싫어하지 않도록 노력해볼게.","JPN":"ううん。グリンダがそう言うなら、私もその人が嫌いにならないように頑張ってみるよ。","ENG":"Never mind. If Glinda says so, I’ll try to not hate him so much.","TWN":"不，既然格琳達這麼說，那我也會努力不討厭他的。"},"stage":{"bg":"NIGHTMARE_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"웬일이야. 내 말을 다 듣고.","JPN":"珍しいじゃん。私の言うこと聞くなんて。","ENG":"Hmm? So now you listen to me?","TWN":"天要下紅雨啦？竟然會聽我的話。"},"stage":{"bg":"NIGHTMARE_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NIGHTMARE_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그러고 보니 내가 아주 오랜만에 개운하게 잔 것도 다 네 덕분인가 봐.","JPN":"そういえば私が久々にめっちゃよく寝れたのも、アンタのおかげだったんだね。","ENG":"Come to think of it, I think the reason why I slept so well is all thanks to you.","TWN":"這麼說來，我可以久違地睡個好覺，應該也是拜你所賜囉？"},"stage":{"bg":"NIGHTMARE_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"왠지. 내가 악몽을 안 꿀 리가 없는데. 아직도 믿기지가 않네.","JPN":"どうりで。私が悪夢を見ないわけないのに。いまだに信じられないよ。","ENG":"I still can’t believe that I didn’t have a nightmare last time.","TWN":"我想說我怎麼可能不做惡夢，到現在還有點不敢置信呢。"},"stage":{"bg":"NIGHTMARE_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NIGHTMARE_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"악몽을 가져가는 능력이라. 로맨틱한데?","JPN":"悪夢を持っていく能力ねぇ。ロマンチックじゃん？","ENG":"An ability that takes away nightmares... Sounds kinda romantic, no?","TWN":"你的能力是可以把惡夢帶走嗎？真是浪漫的能力。"},"stage":{"bg":"NIGHTMARE_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"생각만큼 그렇게 로맨틱하진 않을 거야.","JPN":"考えているよりもロマンチックじゃないよ。","ENG":"It’s not as romantic as you think.","TWN":"才沒有你想得那麼浪漫。"},"stage":{"bg":"NIGHTMARE_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……이 불꽃을 보고도? 보다 보니 색도 오묘하고 그야말로 로맨틱 덩어린데.","JPN":"……こんな炎なのに？　見てみると色も不思議だし、まさにロマンチックの塊じゃない？","ENG":"Even after seeing that flame? I mean, even the color is so mesmerizing...!","TWN":"……這團火也是，顏色很特別，看起來也是蠻浪漫的。"},"stage":{"bg":"NIGHTMARE_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"그래 봤자 악몽일 뿐이야.","JPN":"それでもただの悪夢だよ。","ENG":"Still, it’s just a nightmare.","TWN":"但這就只是惡夢而已。"},"stage":{"bg":"NIGHTMARE_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"사람을 괴롭히는 일밖에 할 수 없는…… 악몽.","JPN":"人を苦めることしかできない……悪夢。","ENG":"A nightmare that... only causes pain and suffering to people...","TWN":"只會折磨人的……惡夢。"},"stage":{"bg":"NIGHTMARE_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그래도 너처럼 이렇게 악몽을 가져가 주는 사람도 있잖아. 이해는 안 가지만.","JPN":"でもアンタのように、こうやって悪夢を持っていってくれる人もいるだろ。理解はできないけど。","ENG":"But there’re people like you who take them away. Even if it’s hard to wrap my head around it.","TWN":"話雖如此，但也是有像你一樣，可以把惡夢帶走的人嘛，雖然我是不太懂。"},"stage":{"bg":"NIGHTMARE_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"야, 그런데 악몽을 가져가면 너한테는 뭐가 좋은 거야? 힘이 더 강해진다거나 그래?","JPN":"ねえ、ところで悪夢を持っていくとアンタには何がいいわけ？　力がもっと強くなるとか？","ENG":"Oh, but what good is it if you take their nightmares? Do you get stronger over time?","TWN":"不過，把惡夢帶走對你有什麼好處？是能力會變得更強嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"……글쎄.","JPN":"……さあ。","ENG":"I dunno...","TWN":"這個嘛……"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"오히려 약해질 수도.","JPN":"むしろ弱くなるかも。","ENG":"I could get weaker...","TWN":"反而有可能變弱。"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그럼 왜 가져가는 건데? 그냥 호의로?","JPN":"じゃあ、なんで持っていくの？　ただの好意？","ENG":"Then why do you take them? Just out of goodwill?","TWN":"那為什麼要帶走惡夢？出於善意？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"……호의가 아니야. 내가 해야만 하는 일이니까.","JPN":"……好意じゃないよ。私がやらなきゃいけない仕事だから。","ENG":"No. It’s something that I have to do.","TWN":"……不是出於善意，只是盡我的本分。"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그런 게 어딨어. 누가 악몽 가져가준다고 돈을 주는 것도 아닌데 굳이……","JPN":"何それ。悪夢を持っていったってお金をくれるわけでもないのに、わざわざ……","ENG":"What’s that supposed to mean? It’s not like those people pay you to get rid of the night─","TWN":"哪有這種事？又沒人付錢叫你把惡夢帶走，幹嘛……"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":" 음?","JPN":" ん？","ENG":" Huh?","TWN":"嗯？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"글린다? 왜 그래?","JPN":"グリンダ？　どうしたの？","ENG":"Glinda? What’s wrong?","TWN":"格琳達？你在想什麼？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"잠시… 잠시만…….","JPN":"待って……待ってよ……","ENG":"Wait... Hold on a sec...","TWN":"等等…我想想……"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"이거…… 괜찮은데?","JPN":"これ……いけるんじゃない？","ENG":"That’s... not such a bad idea.","TWN":"這……好像可行喔？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"……으응?","JPN":"……うん？","ENG":"...Hmm?","TWN":"……什麼？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};